"use client";

import { cn } from "@workspace/ui/lib/utils";

import type {
  CanvasNodeStatus as CanvasNodeStatusData,
  CanvasNodeVisualStatusTone,
} from "./canvas-node.types";

interface StatusVisual {
  breathing: boolean;
  dotClassName: string;
  pillClassName: string;
  textClassName: string;
}

const GREEN: StatusVisual = {
  breathing: true,
  dotClassName: "bg-green-500",
  pillClassName: "bg-green-500/30 text-zinc-50",
  textClassName: "text-green-500",
};
const BLUE: StatusVisual = {
  breathing: true,
  dotClassName: "bg-blue-500",
  pillClassName: "bg-blue-500/30 text-zinc-50",
  textClassName: "text-blue-500",
};
const YELLOW: StatusVisual = {
  breathing: true,
  dotClassName: "bg-yellow-500",
  pillClassName: "bg-yellow-500/30 text-zinc-50",
  textClassName: "text-yellow-500",
};
const GRAY_STATIC: StatusVisual = {
  breathing: false,
  dotClassName: "bg-neutral-500",
  pillClassName: "bg-neutral-500/30 text-zinc-50",
  textClassName: "text-neutral-400",
};
const RED: StatusVisual = {
  breathing: true,
  dotClassName: "bg-red-500",
  pillClassName: "bg-red-500/30 text-zinc-50",
  textClassName: "text-red-500",
};

export const DEFAULT_CANVAS_NODE_STATUS = {
  label: "Unknown",
  visualTone: "neutral",
} as const satisfies CanvasNodeStatusData;

export function normalizeCanvasNodeVisualTone(
  input: string | undefined
): CanvasNodeVisualStatusTone {
  const normalized = input
    ?.trim()
    .toLowerCase()
    .replace(/[\s_]+/g, "-");

  switch (normalized) {
    case "positive":
      return normalized;
    case "progress":
      return normalized;
    case "warning":
      return normalized;
    case "negative":
      return normalized;
    case "neutral":
      return normalized;
    default:
      return "neutral";
  }
}

export function resolveCanvasNodeStatus(
  status: CanvasNodeStatusData | undefined
): Required<CanvasNodeStatusData> {
  return {
    label: status?.label?.trim() || DEFAULT_CANVAS_NODE_STATUS.label,
    visualTone: normalizeCanvasNodeVisualTone(status?.visualTone),
  };
}

function getStatusVisual(tone: CanvasNodeVisualStatusTone): StatusVisual {
  switch (tone) {
    case "positive":
      return GREEN;
    case "progress":
      return BLUE;
    case "warning":
      return YELLOW;
    case "negative":
      return RED;
    case "neutral":
      return GRAY_STATIC;
    default:
      return GRAY_STATIC;
  }
}

export function getCanvasNodeStatusTextClassName(
  status: CanvasNodeStatusData | undefined
) {
  const resolvedStatus = resolveCanvasNodeStatus(status);
  return getStatusVisual(resolvedStatus.visualTone).textClassName;
}

export function CanvasNodeStatusDot({
  className,
  size = "default",
  status,
}: {
  className?: string;
  size?: "collapsed" | "default" | "small";
  status?: CanvasNodeStatusData;
}) {
  const resolvedStatus = resolveCanvasNodeStatus(status);
  const visual = getStatusVisual(resolvedStatus.visualTone);
  const dotSize = size === "default" ? "size-3" : "size-2";
  const pingSize = size === "default" ? "size-2.5" : "size-2";

  return (
    <span
      aria-hidden
      className={cn(
        "relative flex shrink-0 items-center justify-center rounded-full",
        size === "default" ? "size-4" : "size-3.5",
        className
      )}
    >
      {visual.breathing ? (
        <span
          className={cn(
            "absolute animate-ping rounded-full opacity-75",
            pingSize,
            visual.dotClassName
          )}
        />
      ) : null}
      <span
        className={cn("relative rounded-full", dotSize, visual.dotClassName)}
      />
    </span>
  );
}

export function CanvasNodeStatusPill({
  className,
  status,
}: {
  className?: string;
  status?: CanvasNodeStatusData;
}) {
  const resolvedStatus = resolveCanvasNodeStatus(status);
  const visual = getStatusVisual(resolvedStatus.visualTone);

  return (
    <span
      className={cn(
        "flex h-5 shrink-0 items-center gap-2.5 rounded-full py-0.5 pr-1 pl-2.5 font-normal text-xs leading-none",
        visual.pillClassName,
        className
      )}
    >
      <span className="truncate">{resolvedStatus.label}</span>
      <CanvasNodeStatusDot size="small" status={status} />
    </span>
  );
}

export function CanvasNodeStatus({
  className,
  status,
}: {
  className?: string;
  status?: CanvasNodeStatusData;
}) {
  return (
    <span
      className={cn(
        "canvas-node-status flex size-8 shrink-0 items-center justify-center",
        className
      )}
    >
      <CanvasNodeStatusDot
        className="canvas-node-status-dot"
        size="collapsed"
        status={status}
      />
    </span>
  );
}

.canvas-node-frame {
  --canvas-node-surface-base: color-mix(
    in oklab,
    var(--color-white) 4.5%,
    transparent
  );
  --canvas-node-surface-active-bg: transparent;
  --canvas-node-card-width: calc(var(--spacing) * 68);
  --canvas-node-card-height-collapsed: calc(var(--spacing) * 15.5);
  --canvas-node-control-size: calc(var(--spacing) * 8);
  --canvas-node-control-gap: calc(var(--spacing) * 1.5);
  --canvas-node-connection-size: calc(var(--spacing) * 5);
  --canvas-node-connection-gap: calc(var(--spacing) * 1.5);
  --canvas-node-edge-highlight-size: calc(var(--spacing) * 0.25);
  display: grid;
  grid-template-columns:
    var(--canvas-node-control-size) var(--canvas-node-control-gap)
    var(--canvas-node-card-width);
  align-items: start;
  width: calc(
    var(--canvas-node-control-size) +
    var(--canvas-node-control-gap) +
    var(--canvas-node-card-width)
  );
  min-height: var(--canvas-node-card-height-collapsed);
  cursor: default;
  transition: min-height 180ms cubic-bezier(0.16, 1, 0.3, 1);
}

.canvas-node-frame:is([data-hover-intent], [data-dragging], [data-selected]) {
  --canvas-node-surface-active-bg: color-mix(
    in oklab,
    var(--color-zinc-950) 20%,
    transparent
  );
}

.canvas-node-surface {
  grid-row: 1;
  grid-column: 3;
  width: var(--canvas-node-card-width);
  min-height: var(--canvas-node-card-height-collapsed);
  background:
    linear-gradient(
      90deg,
      var(--canvas-node-surface-base) 0%,
      var(--canvas-node-surface-base) 100%
    ),
    linear-gradient(
      90deg,
      var(--canvas-node-surface-active-bg) 0%,
      var(--canvas-node-surface-active-bg) 100%
    );
  transition:
    background 150ms ease-out,
    border-color 150ms ease-out,
    box-shadow 150ms ease-out;
}

.react-flow__node.draggable .canvas-node-surface {
  cursor: default;
}

.react-flow__node.draggable.dragging .canvas-node-surface {
  cursor: grabbing;
}

.canvas-node-frame:is([data-dragging], [data-selected]) .canvas-node-surface {
  border-color: var(--color-blue-400);
}

.canvas-node-frame[data-hover-side="top"] .canvas-node-surface {
  box-shadow: 0 calc(var(--canvas-node-edge-highlight-size) * -1) 0 0
    var(--color-blue-400);
}

.canvas-node-frame[data-hover-side="right"] .canvas-node-surface {
  box-shadow: var(--canvas-node-edge-highlight-size) 0 0 0 var(--color-blue-400);
}

.canvas-node-frame[data-hover-side="bottom"] .canvas-node-surface {
  box-shadow: 0 var(--canvas-node-edge-highlight-size) 0 0 var(--color-blue-400);
}

.canvas-node-frame[data-hover-side="left"] .canvas-node-surface {
  box-shadow: calc(var(--canvas-node-edge-highlight-size) * -1) 0 0 0
    var(--color-blue-400);
}

.canvas-node-header {
  min-height: var(--canvas-node-card-height-collapsed);
  padding: calc(var(--spacing) * 2.5);
  border-bottom: 0.5px solid transparent;
  transition: border-color 150ms ease-out;
}

.canvas-node-frame[data-state="expanded"] .canvas-node-header {
  border-bottom-color: color-mix(in oklab, var(--color-white) 10%, transparent);
}

.canvas-node-header-content {
  display: flex;
  flex-direction: column;
}

.canvas-node-body {
  display: grid;
  grid-template-rows: 0fr;
  overflow: hidden;
  opacity: 0;
  transition:
    grid-template-rows 150ms cubic-bezier(0.16, 1, 0.3, 1),
    opacity 100ms ease;
}

.canvas-node-frame[data-state="expanded"] .canvas-node-body {
  grid-template-rows: 1fr;
  opacity: 1;
  transition-delay: 40ms, 40ms;
  transition-duration: 180ms, 120ms;
}

.canvas-node-body-clip {
  min-height: 0;
  padding: 0 calc(var(--spacing) * 2.5);
  overflow: hidden;
  transition: padding-bottom 150ms cubic-bezier(0.16, 1, 0.3, 1);
}

.canvas-node-frame[data-state="expanded"] .canvas-node-body-clip {
  padding-bottom: calc(var(--spacing) * 2.5);
  transition-delay: 40ms;
  transition-duration: 180ms;
}

.canvas-node-footer {
  min-height: calc(var(--spacing) * 10);
  padding: calc(var(--spacing) * 2.5);
  border-top: 0.5px solid
    color-mix(in oklab, var(--color-white) 10%, transparent);
}

.canvas-node-copyable-row[data-copyable]:hover,
.canvas-node-copyable-row:has(.canvas-node-copyable-row-hitarea:focus-visible) {
  background: color-mix(in oklab, var(--color-white) 4.5%, transparent);
}

.canvas-node-connection-layer {
  top: 0;
  bottom: 0;
  left: calc(var(--canvas-node-control-size) + var(--canvas-node-control-gap));
  z-index: 1;
  width: var(--canvas-node-card-width);
}

.canvas-node-connection-button {
  width: var(--canvas-node-connection-size);
  height: var(--canvas-node-connection-size);
  overflow: visible;
  pointer-events: none;
  background: transparent;
  border: 0;
  opacity: 0;
  transition: opacity 150ms ease;
}

.canvas-node-connection-button::before,
.canvas-node-connection-button::after {
  position: absolute;
  content: "";
}

.canvas-node-connection-button::before {
  background: transparent;
}

.canvas-node-connection-button::after {
  inset: 0;
  z-index: 0;
  background:
    linear-gradient(
      90deg,
      var(--canvas-node-surface-base) 0%,
      var(--canvas-node-surface-base) 100%
    ),
    linear-gradient(
      90deg,
      color-mix(in oklab, var(--color-zinc-950) 20%, transparent) 0%,
      color-mix(in oklab, var(--color-zinc-950) 20%, transparent) 100%
    );
  border: 0.5px solid color-mix(in oklab, var(--color-white) 10%, transparent);
  border-radius: inherit;
  backdrop-filter: blur(8px);
  transform-origin: center;
  scale: 0.4;
  transition:
    scale 150ms ease,
    background 150ms ease,
    border 150ms ease;
}

.canvas-node-frame[data-state="expanded"]:not([data-dragging]):is(
    [data-hover-intent],
    [data-selected]
  )
  .canvas-node-connection-button {
  pointer-events: auto;
  opacity: 1;
}

.canvas-node-connection-button:hover::after {
  background: color-mix(in oklab, var(--color-white) 5%, transparent);
  border: 1px solid var(--color-blue-400);
  scale: 1;
}

.canvas-node-connection-icon {
  position: relative;
  z-index: 1;
  color: var(--color-zinc-50);
  opacity: 0;
  transition: opacity 150ms ease;
}

.canvas-node-connection-button:hover .canvas-node-connection-icon {
  opacity: 1;
}

.canvas-node-connection-button[data-side="top"] {
  top: 0;
  left: 50%;
  translate: -50% calc(-100% - var(--canvas-node-connection-gap));
}

.canvas-node-connection-button[data-side="top"]::before {
  top: 100%;
  right: 0;
  left: 0;
  height: var(--canvas-node-connection-gap);
}

.canvas-node-connection-button[data-side="right"] {
  top: 50%;
  right: 0;
  translate: calc(100% + var(--canvas-node-connection-gap)) -50%;
}

.canvas-node-connection-button[data-side="right"]::before {
  top: 0;
  right: 100%;
  bottom: 0;
  width: var(--canvas-node-connection-gap);
}

.canvas-node-connection-button[data-side="bottom"] {
  bottom: 0;
  left: 50%;
  translate: -50% calc(100% + var(--canvas-node-connection-gap));
}

.canvas-node-connection-button[data-side="bottom"]::before {
  right: 0;
  bottom: 100%;
  left: 0;
  height: var(--canvas-node-connection-gap);
}

.canvas-node-connection-button[data-side="left"] {
  top: 50%;
  left: 0;
  translate: calc(-100% - var(--canvas-node-connection-gap)) -50%;
}

.canvas-node-connection-button[data-side="left"]::before {
  top: 0;
  bottom: 0;
  left: 100%;
  width: var(--canvas-node-connection-gap);
}

.canvas-node-action-button:hover,
.canvas-node-action-button:focus-visible,
.canvas-node-action-menu-trigger:hover,
.canvas-node-action-menu-trigger:focus-visible {
  background: color-mix(in oklab, var(--color-white) 4.5%, transparent);
}

.canvas-node-action-menu-content {
  backdrop-filter: blur(calc(var(--spacing) * 5));
}

.canvas-node-action-menu-item[data-highlighted] {
  color: var(--color-zinc-50);
  background: color-mix(in oklab, var(--color-white) 15%, transparent);
}

.canvas-node-action-menu-item:is(
    :hover,
    :focus,
    [data-highlighted]
  )[data-tone="info"]
  svg {
  color: var(--color-blue-400);
  stroke: var(--color-blue-400);
}

.canvas-node-action-menu-item:is(
    :hover,
    :focus,
    [data-highlighted]
  )[data-tone="destructive"]
  svg {
  color: var(--color-red-500);
  stroke: var(--color-red-500);
}

.canvas-node-action-menu-item:is(
    :hover,
    :focus,
    [data-highlighted]
  )[data-tone="muted"]
  svg {
  color: var(--muted-foreground);
  stroke: var(--muted-foreground);
}

.canvas-node-action-menu-item:is(
    :hover,
    :focus,
    [data-highlighted]
  )[data-tone="success"]
  svg {
  color: var(--color-green-500);
  stroke: var(--color-green-500);
}

.canvas-node-card-frame {
  position: relative;
  grid-row: 1;
  grid-column: 3;
}

.canvas-node-card-frame::before {
  position: absolute;
  inset: calc(var(--spacing) * -1);
  pointer-events: none;
  content: "";
  background: var(--canvas-node-surface-base);
  border-radius: inherit;
  opacity: 0;
  transition: opacity 150ms ease-out;
}

.canvas-node-frame:is([data-hover-intent], [data-dragging], [data-selected])
  .canvas-node-card-frame::before {
  opacity: 1;
}

.canvas-node-drag-frame::after {
  --canvas-node-drag-stroke: color-mix(
    in oklab,
    var(--color-white) 15%,
    transparent
  );
  --canvas-node-drag-stroke-clear: transparent;
  position: absolute;
  inset: -4px;
  padding: 1px;
  pointer-events: none;
  content: "";
  background:
    linear-gradient(
      135deg,
      var(--canvas-node-drag-stroke) 0%,
      var(--canvas-node-drag-stroke-clear) 18%
    ),
    linear-gradient(
      135deg,
      var(--canvas-node-drag-stroke) 0%,
      var(--canvas-node-drag-stroke-clear) 18%
    ),
    linear-gradient(
      315deg,
      var(--canvas-node-drag-stroke) 0%,
      var(--canvas-node-drag-stroke-clear) 18%
    ),
    linear-gradient(
      315deg,
      var(--canvas-node-drag-stroke) 0%,
      var(--canvas-node-drag-stroke-clear) 18%
    );
  border-radius: inherit;
  -webkit-mask:
    linear-gradient(#000 0 0) content-box,
    linear-gradient(#000 0 0);
  mask:
    linear-gradient(#000 0 0) content-box,
    linear-gradient(#000 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
}

.canvas-node-expand-button {
  --canvas-node-expand-underlay: transparent;
  position: absolute;
  top: 0;
  left: 0;
  width: var(--canvas-node-control-size);
  height: var(--canvas-node-control-size);
  color: var(--color-zinc-400);
  pointer-events: none;
  cursor: pointer;
  background:
    linear-gradient(
      90deg,
      var(--canvas-node-surface-base) 0%,
      var(--canvas-node-surface-base) 100%
    ),
    linear-gradient(
      90deg,
      var(--canvas-node-expand-underlay) 0%,
      var(--canvas-node-expand-underlay) 100%
    );
  opacity: 0;
  transition:
    opacity 150ms ease,
    background 150ms ease,
    color 150ms ease;
}

.canvas-node-frame:not([data-dragging]):is([data-hover-intent], [data-selected])
  .canvas-node-expand-button {
  pointer-events: auto;
  opacity: 1;
}

.canvas-node-expand-button:hover {
  --canvas-node-expand-underlay: var(--canvas-node-surface-active-bg);
  color: var(--color-blue-400);
}

